import { Col, Divider, Modal, Row, Tag, Typography } from "antd"
import PropTypes from "prop-types"
import TitleCustom from "src/components/TitleCustom"

const { Text } = Typography

const DetailModal = ({ open, onCancel, data }) => {
  if (!data) return null

  const formatCurrency = val =>
    new Intl.NumberFormat("vi-VN", {
      style: "currency",
      currency: "VND",
    }).format(val)


  return (
    <Modal
      open={open}
      onCancel={onCancel}
      footer={null}
      width={720}
    >
      <TitleCustom>Chi tiết gói quảng cáo</TitleCustom>
      <Row gutter={[24, 16]}>
        <Col span={12}>
          <Text type="secondary">Vị trí</Text>
          <div style={{ fontWeight: 500 }}>{data.Position}</div>
        </Col>
        <Col span={12}>
          <Text type="secondary">Giá</Text>
          <div style={{ color: "#1677ff", fontWeight: 600, fontSize: 16 }}>
            {formatCurrency(data.Price)}
          </div>
        </Col>
      </Row>

      <Divider />

      <Row gutter={[24, 16]}>
        <Col span={12}>
          <Text type="secondary">Mô tả</Text>
          <div style={{ whiteSpace: "pre-line" }}>
            {data.Description || "Không có mô tả"}
          </div>
        </Col>
        <Col span={12}>
          <Text type="secondary">Trạng thái</Text>
          <div>
            {data.Status === 0 ? (
              <Tag color="red">Không có hợp đồng quảng cáo</Tag>
            ) : (
              <Tag color="green">Có hợp đồng quảng cáo</Tag>
            )}
          </div>
        </Col>
      </Row>
    </Modal>
  )
}

DetailModal.propTypes = {
  open: PropTypes.bool.isRequired,
  onCancel: PropTypes.func.isRequired,
  data: PropTypes.shape({
    PackageID: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    Position: PropTypes.string,
    Price: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    Duration: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    Description: PropTypes.string,
    Status: PropTypes.number,
  }),
}

export default DetailModal
