import { Col, Form, Input, Modal, Row, message } from "antd"
import PropTypes from "prop-types"
import { useEffect } from "react"
import AdvertisementService from "src/services/Advertisement"
import "./UpdateModal.scss"

function UpdateModal({ open, onCancel, onSubmit, data, loading }) {
  const [form] = Form.useForm()

  useEffect(() => {
    if (data) {
      form.setFieldsValue(data)
    } else {
      form.resetFields()
    }
  }, [data, form])

  const handleOk = async () => {
    try {
      const values = await form.validateFields()

      // Chuẩn bị body cho API
      const body = {
        AdPositionId: data?.AdPositionId || undefined,
        Position: values.Position,
        Price: Number(values.Price),
        Description: values.Description || "",
      }

      let res
      if (data) {
        // Update
        res = await AdvertisementService.updateAdvertisingPosition(body)
      } else {
        // Add
        res = await AdvertisementService.addAdvertisingPosition(body)
      }

      if (res?.isError) {
        message.error("Có lỗi xảy ra, vui lòng thử lại!")
        return
      }

      message.success(data ? "Cập nhật thành công!" : "Thêm mới thành công!")
      onSubmit(body) // callback để refresh list
      onCancel()
    } catch (error) {
      console.error("Submit error:", error)
    }
  }

  return (
    <Modal
      title={
        <span className="detail-modal__title">
          {data ? "Chỉnh sửa vị trí quảng cáo" : "Thêm vị trí quảng cáo"}
        </span>
      }
      open={open}
      onCancel={onCancel}
      onOk={handleOk}
      confirmLoading={loading}
      destroyOnClose
      width={700}
      okText="Lưu"
      cancelText="Hủy"
      okButtonProps={{
        className: "detail-modal__ok-btn",
      }}
      cancelButtonProps={{
        className: "detail-modal__cancel-btn",
      }}
      className="detail-modal"
    >
      <Form form={form} layout="vertical" className="detail-modal__form">
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              name="Position"
              label="Tên vị trí"
              rules={[{ required: true, message: "Vui lòng nhập tên vị trí" }]}
            >
              <Input placeholder="Nhập tên vị trí quảng cáo" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              name="Price"
              label="Giá (VND)"
              rules={[{ required: true, message: "Vui lòng nhập giá" }]}
            >
              <Input
                type="number"
                className="w-full"
                min={0}
                onKeyDown={e => {
                  if (e.key === "-" || e.key === "Subtract") {
                    e.preventDefault()
                  }
                }}
                onChange={e => {
                  if (e.target.value < 0) {
                    e.target.value = 0
                  }
                }}
                placeholder="Nhập giá"
              />
            </Form.Item>
          </Col>
        </Row>

        <Row>
          <Col span={24}>
            <Form.Item name="Description" label="Mô tả">
              <Input.TextArea rows={4} placeholder="Nhập mô tả gói quảng cáo" />
            </Form.Item>
          </Col>
        </Row>
      </Form>
    </Modal>
  )
}

UpdateModal.propTypes = {
  open: PropTypes.bool.isRequired,
  onCancel: PropTypes.func.isRequired,
  onSubmit: PropTypes.func.isRequired,
  data: PropTypes.shape({
    AdPositionId: PropTypes.string,
    Position: PropTypes.string,
    Price: PropTypes.number,
    Description: PropTypes.string,
    Status: PropTypes.number,
  }),
  loading: PropTypes.bool,
}

UpdateModal.defaultProps = {
  data: null,
  loading: false,
}

export default UpdateModal
