import { Col, message, Modal, Row, Select } from "antd"
import { useEffect, useState } from "react"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import SelectCustom from "src/components/Select/SelectCustom"
import TableCustom from "src/components/Table/CustomTable"
import TitleCustom from "src/components/TitleCustom"
import SpanText from "src/components/Typography/SpanText"
import UpdateModal from "./components/UpdateModal"
import DetailModal from "./components/DetailModal"
import AdvertisementService from "src/services/Advertisement"

const { Option } = Select

function AdvertisingPackage() {
  const [detailLoading, setDetailLoading] = useState(false)
  const [loading, setLoading] = useState(false)
  const [totalRecords, setTotalRecords] = useState(0)
  const [textSearch, setTextSearch] = useState("")
  const [openModalInsertUpdate, setOpenModalInsertUpdate] = useState(false)
  const [selectedRecord, setSelectedRecord] = useState(null)
  const [modalLoading, setModalLoading] = useState(false)
  const [openDetailModal, setOpenDetailModal] = useState(false)
  const [listData, setListData] = useState([])
  const [pagination, setPagination] = useState({
    PageSize: 20,
    CurrentPage: 1,
    Status: "",
    PositionName: "",
  })

  const getList = async () => {
    try {
      setLoading(true)
      const params = {
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
        Status: pagination.Status,
        PositionName: pagination.PositionName,
      }
      const res = await AdvertisementService.getAllAdvertisingPosition(params)
      if (res?.isError) return
      setListData(res?.Object || [])
      setTotalRecords(
        res?.TotalRecords || (res?.Object ? res.Object.length : 0),
      )
    } catch (error) {
      console.error("fetchList error:", error)
    } finally {
      setLoading(false)
    }
  }

  const confirmActive = record => {
    Modal.confirm({
      title: "Xác nhận kích hoạt",
      content: "Bạn có chắc chắn muốn kích hoạt vị trí quảng cáo này?",
      okText: "Đồng ý",
      cancelText: "Hủy",
      onOk: () => handleActive(record),
    })
  }

  const confirmDeactive = record => {
    Modal.confirm({
      title: "Xác nhận vô hiệu",
      content: "Bạn có chắc chắn muốn vô hiệu hóa vị trí quảng cáo này?",
      okText: "Đồng ý",
      cancelText: "Hủy",
      onOk: () => handleDeactive(record),
    })
  }

  const handleActive = async record => {
    try {
      setLoading(true)
      const res = await AdvertisementService.activeAdvertisingPosition({
        AdPositionId: record.AdPositionId,
      })
      if (res?.isError) {
        message.error(res?.Message || "Kích hoạt thất bại")
        return
      }
      message.success("Kích hoạt thành công")
      getList()
    } catch (error) {
      console.error("handleActive error:", error)
      message.error("Có lỗi xảy ra khi kích hoạt")
    } finally {
      setLoading(false)
    }
  }

  const handleDeactive = async record => {
    try {
      setLoading(true)
      const res = await AdvertisementService.deactiveAdvertisingPosition({
        AdPositionId: record.AdPositionId,
      })
      if (res?.isError) {
        message.error(res?.Message || "Vô hiệu hóa thất bại")
        return
      }
      message.success("Vô hiệu hóa thành công")
      getList()
    } catch (error) {
      console.error("handleDeactive error:", error)
      message.error("Có lỗi xảy ra khi vô hiệu hóa")
    } finally {
      setLoading(false)
    }
  }

  // Handle search and filter
  const handleSearch = () => {
    setPagination(pre => ({ ...pre, PositionName: textSearch, CurrentPage: 1 }))
  }

  const handleSubmit = async () => {
    setModalLoading(true)
    try {
      // Gọi lại getList để reload dữ liệu từ API
      setOpenModalInsertUpdate(false)
      setSelectedRecord(null)
      await getList()
    } catch (error) {
      console.error(error)
    } finally {
      setModalLoading(false)
    }
  }

  const formatCurrency = amount => {
    return new Intl.NumberFormat("vi-VN", {
      style: "currency",
      currency: "VND",
    }).format(amount)
  }

  const columns = [
    {
      title: "STT",
      dataIndex: "index",
      render: (_, __, idx) =>
        idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1),
      width: 70,
      align: "center",
    },
    {
      title: "Vị trí",
      dataIndex: "Position",
      width: 200,
      align: "center",
      render: (text, record) => (
        <div>
          <div className="fw-600 mb-1">{text}</div>
          <div className="text-muted" style={{ fontSize: "12px" }}>
            {record.Position}
          </div>
        </div>
      ),
    },
    {
      title: "Giá",
      dataIndex: "Price",
      align: "center",
      width: 120,
      render: val => (
        <div className="fw-600 text-primary">{formatCurrency(val)}</div>
      ),
    },
    {
      title: "Mô tả",
      dataIndex: "Description",
      align: "center",
      width: 120,
      render: val => `${val}`,
    },
    {
      title: "Trạng thái",
      dataIndex: "IsDelete",
      align: "center",
      width: 120,
      render: val =>
        val === true ? (
          <SpanText type="danger">Vô hiệu</SpanText>
        ) : (
          <SpanText type="success">Kích hoạt</SpanText>
        ),
    },
    {
      title: "Tình trạng hợp đồng",
      dataIndex: "Status",
      align: "center",
      width: 160,
      render: (isStatus, record) => {
        const isActive = isStatus === 1

        return (
          <div>
            <div className="fw-600 mb-2">
              <SpanText type={isActive ? "success" : "danger"}>
                {isActive ? "Đang có hợp đồng" : "Không có hợp đồng"}
              </SpanText>
            </div>

            <FloatActionWrapper size="small" className="float-action__wrapper">
              {/* Edit button luôn hiện */}
              <ButtonCircle
                className="button-circle"
                title="Chỉnh sửa"
                iconName="edit"
                style={{
                  background: "#EDF6FC",
                  boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                }}
                onClick={e => {
                  e.stopPropagation()
                  setSelectedRecord(record)
                  setOpenModalInsertUpdate(true)
                }}
              />

              {/* Active / Deactive với confirm */}
              {record.IsDelete === true ? (
                <ButtonCircle
                  className="button-circle"
                  title="Kích hoạt"
                  iconName="check-circle"
                  style={{
                    background: "#E6F7E6",
                    boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                  }}
                  onClick={e => {
                    e.stopPropagation()
                    confirmActive(record)
                  }}
                />
              ) : (
                <ButtonCircle
                  className="button-circle"
                  title="Vô hiệu"
                  iconName="cancel"
                  style={{
                    background: "#FFE9EC",
                    boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                  }}
                  onClick={e => {
                    e.stopPropagation()
                    confirmDeactive(record)
                  }}
                />
              )}
            </FloatActionWrapper>
          </div>
        )
      },
    },
  ]

  useEffect(() => {
    getList()
  }, [
    pagination.PositionName,
    pagination.Status,
    pagination.CurrentPage,
    pagination.PageSize,
  ])

  // Initialize dataSource with mockData when component mounts
  useEffect(() => {
    getList()
  }, [])
  return (
    <div>
      <Row className="justify-content-space-between align-items-center ">
        <TitleCustom>Cấu hình quảng cáo</TitleCustom>
        <ButtonCustom
          btnType="primary"
          className="btn-hover-shadow"
          onClick={() => {
            setSelectedRecord(null)
            setOpenModalInsertUpdate(true)
          }}
        >
          Thêm mới
        </ButtonCustom>
      </Row>

      <Row
        className="align-items-center pb-8 pt-0 mb-16 mt-16"
        gutter={[16, 16]}
        align="middle"
      >
        <Col span={18}>
          <InputCustom
            type="search"
            allowClear
            label="Tìm kiếm theo vị trí"
            enterButton
            value={textSearch}
            onSearch={handleSearch}
            onChange={e => setTextSearch(e?.target?.value)}
          />
        </Col>

        <Col span={6}>
          <SelectCustom
            label="Trạng thái"
            allowClear
            value={pagination.Status}
            onChange={Status => {
              setPagination(pre => ({ ...pre, Status, CurrentPage: 1 }))
              setTimeout(getList, 0)
            }}
          >
            <Option value="">Tất cả</Option>
            <Option value="1">Hoạt động</Option>
            <Option value="0">Không hoạt động</Option>
          </SelectCustom>
        </Col>
      </Row>

      <TableCustom
        isPrimary
        dataSource={listData}
        columns={columns}
        sticky={{ offsetHeader: -12 }}
        loading={loading}
        textEmpty="Không có vị trí quảng cáo nào!"
        pagination={{
          current: pagination?.CurrentPage,
          pageSize: pagination?.PageSize,
          responsive: true,
          total: totalRecords,
          locale: { items_per_page: "" },
          showSizeChanger: true,
          onChange: (CurrentPage, PageSize) => {
            setPagination({
              ...pagination,
              CurrentPage,
              PageSize,
            })
          },
        }}
        rowKey="PackageID"
        onRow={record => ({
          onClick: async () => {
            try {
              setDetailLoading(true)
              const res =
                await AdvertisementService.getAdvertisingPositionDetail({
                  AdPositionId: record.AdPositionId,
                })
              if (res?.isError) return
              setSelectedRecord(res?.Object || record)
              setOpenDetailModal(true)
            } catch (error) {
              console.error("fetch detail error:", error)
            } finally {
              setDetailLoading(false)
            }
          },
        })}
      />

      <UpdateModal
        open={openModalInsertUpdate}
        onCancel={() => {
          setOpenModalInsertUpdate(false)
          setSelectedRecord(null)
        }}
        onSubmit={handleSubmit}
        data={selectedRecord}
        loading={modalLoading}
      />

      <DetailModal
        open={openDetailModal}
        data={selectedRecord}
        loading={detailLoading}
        onCancel={() => {
          setOpenDetailModal(false)
          setSelectedRecord(null)
        }}
      />
    </div>
  )
}

export default AdvertisingPackage
